var PACardTimerSiv = {};
var PAVerifySiv;

jQuery(function(){

    var PABody = jQuery('body');

    PABody.on('click','.pa-card-identify-btn',function(){
        PACardIdentifyNationalCode();
    });

    PABody.on('blur','.pa-card-field input[name="nationalCode"]',function(){
        PACardCheckFieldNationalCode();
    });

    PABody.on('blur','.pa-card-field input[name="mobileNumber"]',function(){
        PACardCheckFieldMobileNumber();
    });

    PABody.on('keyup paste','.pa-card-code-field input',function(){
        PACardModifyCode(jQuery(this));
    });

    if(jQuery('.pa-card-timer-time').length > 0)
    {
        jQuery('.pa-card-timer-time').each(function(){
            PACardSetTimer(jQuery(this));
        });
    }

});

function PACardSetTimer(element)
{
    let tid = jQuery(this).attr('tid');
    if(!tid)
    {
        tid = 't'+randomNumberFromRange(10000,99999);
        element.attr('tid',tid);
    }

    PACardSetTime(element);

    PACardTimerSiv[tid] = setInterval(function(){
        PACardSetTime(element);
    },1000);
}

function PACardSetTime(element)
{
    let time = element.attr('time');
    times = PACalculateTimerTimes(time,true);
    element.html(times['min']+':'+times['sec']);
    element.attr('time',time-1);

    if(time <= 0)
    {
        clearInterval(PACardTimerSiv[element.attr['tid']]);
    }
}

function PACardIdentifyNationalCode()
{
    jQuery('.pa-card-msg').html('');

    let card = jQuery('[name="card"]').val();
    let nationalCode = jQuery('[name="nationalCode"]').val();
    let mobileNumber = jQuery('[name="mobileNumber"]').val();

    let nationalCodeCheck = PACardCheckFieldNationalCode();
    let mobileNumberCheck = PACardCheckFieldMobileNumber();

    if(!nationalCodeCheck || !mobileNumberCheck)
    {
        return;
    }

    jQuery('.pa-card-identify-btn').addClass('pa-disable-btn');

    jQuery.ajax({
        type: 'POST',
        url: PAUrls['identifyNationalCode'],
        data: {
            'card' : card,
            'nationalCode' : nationalCode,
            'mobileNumber' : mobileNumber
        },
        success:function(result)
        {
            result = jsonDecode(result,[0,PALanguages['PA_UNKNOWN_ERROR']]);

            jQuery('.pa-card-identify-btn').removeClass('pa-disable-btn');

            if(result[0] == 1)
            {
                jQuery('.pa-card-mobile-number').html(result[2]['mobileNumber']);

                PACardStepSlide(2);
                jQuery('.pa-card-send-again-timer').attr('time',179);
                PACardSetTimer(jQuery('.pa-card-send-again-timer'));
            }
            else
            {
                jQuery('.pa-card-msg').html(getMsgHtml(0,result[1],''));
                jQuery('.pa-card-msg .pa-bt-msg').fadeIn(500);
            }
        },
        error: PALoadAjaxError,
        timeout: 60000
    });

}

function PACardStepSlide(sid)
{
    jQuery('.pa-card-step[sid="'+(sid-1)+'"] .pa-card-step-content').slideUp(250);
    jQuery('.pa-card-step[sid="'+(sid)+'"] .pa-card-step-content').slideDown(350);
}

function PACardIdentifyCheck()
{
    PACardCheckFieldNationalCode();
    PACardCheckFieldMobileNumber();
}

function PACardCheckFieldNationalCode()
{
    let nationalCode = jQuery('[name="nationalCode"]').val();

    if(!nationalCode || nationalCode.length <= 0)
    {
        PACardFieldSetError('nationalCode',0,PALanguages['PA_CK_GW_CARD_NATIONAL_CODE_EMPTY']);
        return false;
    }
    else if(nationalCode.length != 10)
    {
        PACardFieldSetError('nationalCode',0,PALanguages['PA_CK_GW_CARD_NATIONAL_CODE_INVALID']);
        return false;
    }

    PACardFieldSetError('nationalCode',1,'');
    return true;
}
function PACardCheckFieldMobileNumber()
{
    let mobileNumber = jQuery('[name="mobileNumber"]').val();

    if(!mobileNumber || mobileNumber.length <= 0)
    {
        PACardFieldSetError('mobileNumber',0,PALanguages['PA_CK_GW_CARD_MOBILE_NUMBER_EMPTY']);
        return false;
    }
    else if(!validatePhone(mobileNumber))
    {
        PACardFieldSetError('mobileNumber',0,PALanguages['PA_CK_GW_CARD_MOBILE_NUMBER_INVALID']);
        return false;
    }

    PACardFieldSetError('mobileNumber',1,'');
    return true;
}

function PACardFieldSetError(field,stat,text)
{
    let element = jQuery('.pa-card-field[field="'+field+'"]');
    element.attr('stat',stat);
    element.find('.pa-card-field-msg').html(text);
}

function PACardModifyCode(element)
{
    let value = element.val();

    if(/^\d{1}$/.test(value))
    {
        let index = element.index();

        if(index == jQuery('.pa-card-code-field input').length-1)
        {
            jQuery('.pa-card-code-field input:last-child').blur();
            PACardConfirmCode();
        }
        else
        {
            jQuery('.pa-card-code-field input:eq('+(index+1)+')').focus();
        }
    }
    else
    {
        element.val('');
    }
}

function PACardConfirmCode()
{
    let code = '';

    jQuery('.pa-card-msg').html('');

    jQuery('.pa-card-code-field input').each(function(){
        code += jQuery(this).val();
    });

    jQuery('.pa-card-confirm-code').addClass('pa-disable-btn');

    jQuery.ajax({
        type: 'POST',
        url: PAUrls['confirmCode'],
        data: {
            'code' : code
        },
        success:function(result)
        {
            result = jsonDecode(result,[0,PALanguages['PA_UNKNOWN_ERROR']]);

            jQuery('.pa-card-confirm-code').removeClass('pa-disable-btn');

            if(result[0] == 1)
            {
                jQuery('.pa-card-amount').html(result[2]['amount']);
                jQuery('.pa-card-card').html(result[2]['cardNumber']);
                jQuery('.pa-card-name').html(result[2]['accountName']);

                PACardStepSlide(3);
                PACardCheckVerified();
            }
            else
            {
                jQuery('.pa-card-code-field input').val('');

                var warningIcon = 'pa-icon-triangle-exclamation';
                jQuery('.pa-card-msg').html(getMsgHtml(0,result[1],warningIcon));
                jQuery('.pa-card-msg .pa-bt-msg').fadeIn(500);
            }

        },
        error: PALoadAjaxError,
        timeout: 60000
    });
}

function PACardCheckVerified()
{
    PAVerifySiv = setInterval(function(){
        PACardCheckVerifiedRequest();
    },10000);
}

function PACardCheckVerifiedRequest() {
    jQuery.ajax({
        type: 'POST',
        url: PAUrls['checkVerified'],
        data: {
            'isAjax' : true
        },
        success:function(result)
        {
            result = jsonDecode(result,[0,PALanguages['PA_UNKNOWN_ERROR']]);

            if(result[0] == 1)
            {
                PACardStepSlide(4);
                clearInterval(PAVerifySiv);
                PARedirect(result[2]['url']);
            }

        },
        error: PALoadAjaxError,
        timeout: 60000
    });
}

